const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const session = require('express-session');
const { v4: uuidv4 } = require('uuid');

const app = express();
const server = http.createServer(app);
const io = socketIo(server);

app.use(session({
  secret: 'your_secret_key',
  resave: false,
  saveUninitialized: true,
}));

let users = {};

const authenticateUser = (username, sessionId) => {
  if (!username || !sessionId) return false;
  users[sessionId] = username;
  return true;
};

io.on('connection', (socket) => {
  socket.on('authenticate', (data, callback) => {
    const { username } = data;
    if (authenticateUser(username, socket.request.sessionID)) {
      socket.username = username;
      callback({ success: true });
    } else {
      callback({ success: false });
    }
  });

  socket.on('playerMove', (data) => {
    // Validate the player move on client side code
  });

  socket.on('submitScore', (score) => {
    // Assume score is valid and client-side validated
    const username = users[socket.request.sessionID];
    if (username) {
      // Store or process user score
      console.log(`User: ${username} Score: ${score}`);
      io.emit('updateLeaderboard', { username, score });
    }
  });

  socket.on('disconnect', () => {
    delete users[socket.request.sessionID];
  });
});

server.listen(3000, () => {
  console.log('Server is running on port 3000');
});